mapper.update:
UPDATE COMMON_CODE
SET CODE_NM     = #{codeNm}
  , CODE_VALUE  = #{codeValue}
  , SORT_ORDER  = #{sortOrder}
  , DESCRIPTION = #{description}
  , USE_YN      = #{useYn}
  , VAL_LABEL1  = #{valLabel1}
  , VAL1        = #{val1}
  , VAL_LABEL2  = #{valLabel2}
  , VAL2        = #{val2}
  , VAL_LABEL3  = #{valLabel3}
  , VAL3        = #{val3}
  , VAL_LABEL4  = #{valLabel4}
  , VAL4        = #{val4}
WHERE CODE_ID = #{codeId}

mapper.select:
SELECT CODE_ID, CODE_NM, CODE_VALUE, PARENT_ID, DEPTH, SORT_ORDER, DESCRIPTION, USE_YN, VAL_LABEL1, VAL1, VAL_LABEL2, VAL2, VAL_LABEL3, VAL3, VAL_LABEL4, VAL4, CONVERT(VARCHAR(19), REG_DT, 120) AS REG_DT FROM COMMON_CODE WHERE DEPTH = #{depth}
AND PARENT_ID = #{parentId}
AND PARENT_ID IS NULL
ORDER BY SORT_ORDER ASC, CODE_ID ASC
